var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이런 뒷골목 술집에서 아티팩트를 거래한다니, 역시 인간들은 음험하다니까.","JPN":"こんな裏路地の酒場でアーティファクトを取引するなんて、やっぱり人間は陰険だね～","ENG":"Trading Artifacts in a back alley bar? I knew humans were sneaky.","TWN":"居然在這種小巷的酒吧交易人造神器，人類果然陰險。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"모든 인간들이 학회처럼 음험하다는 편견은 버려 주세요.","JPN":"すべての人間が学会のように陰険だという偏見は捨ててください。","ENG":"Please do not think that all people are insidious like the Society.","TWN":"請放下所有人都像學會一樣陰險的偏見。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"애초에 정말 여기가 맞는지도 확인되지 않았습니다.","JPN":"そもそも、本当にここで合っているかどうかも定かではありません。","ENG":"We do not even know if we are at the right location in the first place.","TWN":"一開始就沒有得到確認，是不是真的在這裡。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"안심하세요, 부학회장님. 종교학부장님께서 가르쳐 주신 곳인 걸요.","JPN":"ご安心ください、副学会長様。宗教学部長様が教えてくださった場所ではないですか。","ENG":"Don't worry, ma'am. The Dean of Religion pointed us here.","TWN":"你放心，副學會長。這裡是宗教學院院長告訴我的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다들 뱃속에 뱀 두어 마리는 키우고 사는 족속들이니 그렇죠.","JPN":"みんな腹の中にヘビの2、3匹は飼ってるような人たちですからね。","ENG":"I am concerned because they all have a hidden agenda that they are not telling us about.","TWN":"我只是不放心那些口蜜腹劍的傢伙們而已。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님은 어떻게 생각하세요?","JPN":"社長はどうお考えですか？","ENG":"What do you think, Boss?","TWN":"老闆是怎麼想的？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 의심은 좋은 습관이라네. 하물며 학회 같은 곳에서라면 더더욱.","JPN":"はは、疑うのはいい習慣だ。学会のようなところなら尚更さ。","ENG":"Haha, having doubts is a good habit. Especially if you're dealing with people from the Society.","TWN":"哈哈，疑心病是個好習慣。在學會這樣的地方尤其如此。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 당장은 다른 도리가 없지 않나. 최대한 신중하게 접근할 수밖에.","JPN":"だが今は別の手がないだろう。できるかぎり慎重に接近するしかあるまい。","ENG":"But, for the time being, we have no choice but to proceed with caution.","TWN":"但是眼下也沒有別的辦法。就只能儘量謹慎對待。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 그렇죠? 그럼 우선 주변을 탐문한 뒤에…….","JPN":"やはりそうですわよね？　それではまず周辺で聞き込みをして……","ENG":"I knew it. Then we should first investigate our surroundings, and–","TWN":"果然是吧？那我們先在周圍調查一番，然後……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"됐네요. 그냥 가서 확인해 보면 되는 거 가지고.","JPN":"いいよ、別に。直接行って確認してみればいいじゃん。","ENG":"Why do that? Let's just go in see what's happening over there.","TWN":"好了，直接進去確認就行了，有什麼可說的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"편하게 돌아다닐 입장이 아니니까요. 남들 눈에 띌수록 골치 아파집니다.","JPN":"気楽に歩き回れる状況ではありません。目立つと困りますわ。","ENG":"Because we are not in a position to be roaming around freely. The more eyes there are on us, the more problematic it becomes.","TWN":"因為我們現在不方便隨便走動。被別人發現就麻煩了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그렇다면 내가 날아가서 슬쩍 보고 오는 건 어때? 어차피 주위는 조용하잖아. ","JPN":"じゃあ、アタシが飛んでいって、そっと見てくるのはどう？　どうせこの辺りは静かなんだし。 ","ENG":"Then how about I swoop in and take a little peek? There's no one around us anyway. ","TWN":"那我飛過去偷看怎麼樣？反正周圍都沒什麼人。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"큰일날 소리 마세요. 남들 눈에 띄면 어쩌려고요?","JPN":"無茶なこと言わないでください。目立ったらどうするつもりですか？","ENG":"Are you serious?! What if someone sees you?","TWN":"你可不要說這種話。如果被人發現怎麼辦？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"히힛. 내가 하루 이틀 날아 본 줄 알아? 들켜도 카운터라고 변명하면 그만이지.","JPN":"へへっ。アタシの飛行経験を無視しないでよね。バレてもカウンターだって言い訳すればいいし。","ENG":"Teehee! It's not my first time flying, you know? If I get caught, I'll just say I'm a Counter.","TWN":"嘻嘻，你以為我第一天在天上飛嗎？如果被人發現，只要說自己是制裁者就行了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"여기서 기다리고 있어! 눈 깜빡할 사이에 다녀올 테니까!","JPN":"ここで待ってて！　あっという間に行ってくるから！","ENG":"Just wait here! I'll be back in a flash!","TWN":"你們在這裡等著！我一會兒就回來！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"잠깐만요! 당신도 상태가……!","JPN":"待ってください！　あなたの具合も……！","ENG":"Wait! But you are...!","TWN":"等等！你的狀態也……！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가 버렸네. 하아, 골치야…….","JPN":"行ってしまったわ。はあ、頭痛い……","ENG":"And there she goes... Ooh, my head...","TWN":"飛走了呢，唉，真讓人頭痛……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};